SELECT a.id, a.staff_id, s.sname, a.date, a.check_in_time, a.check_out_time, a.late_min, a.early_min, a.status, a.reason, a.create_time,
d.dname as departmentName, j.jname as jobName FROM attendance a LEFT JOIN staffs s ON a.staff_id = s.id
LEFT JOIN departments d ON s.dept_id = d.id LEFT JOIN jobs j ON s.job_id = j.id
AND a.staff_id = #{staffId}
AND s.dept_id = #{deptId}
AND a.status = #{status}
AND a.date >= #{startDate}
AND a.date <= #{endDate}
AND DATE_FORMAT(a.date, '%Y-%m') = #{month}
AND a.date = #{date}
AND s.sname LIKE CONCAT('%', #{staffName}, '%')
ORDER BY a.date DESC, a.create_time DESC
LIMIT #{offset}, #{limit}

