SELECT 
FROM attendance
WHERE staff_id = #{staffId}
AND DATE_FORMAT(date, '%Y-%m') = #{month}
ORDER BY date

SELECT a.id, a.staff_id, s.sname, a.date, a.check_in_time, a.late_min, a.reason, d.dname as departmentName, j.jname as jobName FROM attendance a LEFT JOIN staffs s ON a.staff_id = s.id LEFT JOIN departments d ON s.dept_id = d.id LEFT JOIN jobs j ON s.job_id = j.id WHERE (a.status = '迟到' OR a.status = '迟到早退') AND DATE_FORMAT(a.date, '%Y-%m') = #{month}
AND s.dept_id = #{deptId}
ORDER BY a.date DESC, a.late_min DESC

SELECT a.id, a.staff_id, s.sname, a.date, a.check_out_time, a.early_min, a.reason, d.dname as departmentName, j.jname as jobName FROM attendance a LEFT JOIN staffs s ON a.staff_id = s.id LEFT JOIN departments d ON s.dept_id = d.id LEFT JOIN jobs j ON s.job_id = j.id WHERE (a.status = '早退' OR a.status = '迟到早退') AND DATE_FORMAT(a.date, '%Y-%m') = #{month}
AND s.dept_id = #{deptId}
ORDER BY a.date DESC, a.early_min DESC

SELECT s.id as staff_id, s.sname, d.dname as departmentName, j.jname as jobName, #{month} as date, COUNT(*) as absentDays FROM staffs s LEFT JOIN departments d ON s.dept_id = d.id LEFT JOIN jobs j ON s.job_id = j.id WHERE s.id NOT IN ( SELECT DISTINCT staff_id FROM attendance WHERE DATE_FORMAT(date, '%Y-%m') = #{month} AND date IS NOT NULL ) AND s.id IS NOT NULL
AND s.dept_id = #{deptId}
GROUP BY s.id, s.sname, d.dname, j.jname

